118: absl::StatusOr<HeaderParserPtr>
119: HeaderParser::configure(const Protobuf::RepeatedPtrField<HeaderValueOption>& headers_to_add,
120:                         const Protobuf::RepeatedPtrField<std::string>& headers_to_remove) {
121:   auto parser_or_error = configure(headers_to_add);
122:   RETURN_IF_NOT_OK_REF(parser_or_error.status());
123:   HeaderParserPtr header_parser = std::move(parser_or_error.value());
124: 
125:   header_parser->headers_to_remove_.reserve(headers_to_remove.size());
126:   for (const auto& header : headers_to_remove) {
127:     // We reject :-prefix (e.g. :path) removal here. This is dangerous, since other aspects of
128:     // request finalization assume their existence and they are needed for well-formedness in most
129:     // cases.
130:     if (!Http::HeaderUtility::isRemovableHeader(header)) {
131:       return absl::InvalidArgumentError(":-prefixed or host headers may not be removed");
132:     }
133:     header_parser->headers_to_remove_.emplace_back(header);
134:   }
135: 
136:   return header_parser;
